INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('35ddb327-8664-5cc0-a794-d01e9ddae969', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:4128e6d8-3a8a-48c7-bb96-cf8cf0ff6aa2:fb1bbb39-0d85-4bc5-ae58-2ad5a6079d57'), 'fb1bbb39-0d85-4bc5-ae58-2ad5a6079d57', 'Saw it. I''m calling it the event window. If the Thursday batch confirms automation, that week is when someone settled the books.', '[]'::jsonb, now() - interval '1477 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('76ede061-c95a-5feb-ab79-4010d4aa4e02', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:4128e6d8-3a8a-48c7-bb96-cf8cf0ff6aa2:fb1bbb39-0d85-4bc5-ae58-2ad5a6079d57'), '4128e6d8-3a8a-48c7-bb96-cf8cf0ff6aa2', 'If you put ''event window'' on the watchlist page, attach both our ids to it.', '[]'::jsonb, now() - interval '1472 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('aa3568e4-c0d9-530f-b911-258653881c90', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:4128e6d8-3a8a-48c7-bb96-cf8cf0ff6aa2:fb1bbb39-0d85-4bc5-ae58-2ad5a6079d57'), 'fb1bbb39-0d85-4bc5-ae58-2ad5a6079d57', 'Two signals, written down. I know the rules — I wrote them.', '[]'::jsonb, now() - interval '1469 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('b8ace820-8722-55fc-9898-dc50ea0563cd', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:9946155f-cfcb-4ad4-99a4-6b5ed49ad24c'), '9878850d-3024-4012-b03a-d3d7ccef377c', 'Red Meridian: can you hold the referral package until Hannah''s deep verification report? If EV-0055 clears, we amend; if not, the package is already clean.', '[]'::jsonb, now() - interval '1153 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('f4a627fa-49fa-5d50-80d6-9759bbb65e51', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:9946155f-cfcb-4ad4-99a4-6b5ed49ad24c'), '9946155f-cfcb-4ad4-99a4-6b5ed49ad24c', 'Holding until Wednesday noon, then it ships regardless. Legal agrees the shorter list is stronger.', '[]'::jsonb, now() - interval '1149 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('2d59c7d9-58e6-5793-a833-75c8a6bc609a', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:9946155f-cfcb-4ad4-99a4-6b5ed49ad24c'), '9878850d-3024-4012-b03a-d3d7ccef377c', 'Agreed. One more thing — staffing. If the SIM link between Ash Garden and Nightfall verifies, I want one analyst across both.', '[]'::jsonb, now() - interval '1144 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('38f27dda-2894-5931-a5d7-283d09676958', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:9946155f-cfcb-4ad4-99a4-6b5ed49ad24c'), '9946155f-cfcb-4ad4-99a4-6b5ed49ad24c', 'Erik is the obvious pick but he''s at capacity. Priya takes the cross-case node, Erik keeps the patterns.', '[]'::jsonb, now() - interval '1140 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('3e9e41c5-aea1-5653-957c-7a6d1e31c25f', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:9946155f-cfcb-4ad4-99a4-6b5ed49ad24c'), '9878850d-3024-4012-b03a-d3d7ccef377c', 'Good split. Put it in Monday''s triage.', '[]'::jsonb, now() - interval '1137 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('fbd7a2cb-97c1-51ca-bc57-89c018eb1ccd', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:a3cefadb-2668-4f12-830c-14518e0a08f3:edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0'), 'a3cefadb-2668-4f12-830c-14518e0a08f3', 'Friday rotation — can you take the early shift at the static post? Viktor has the courier watch with Nadia.', '[]'::jsonb, now() - interval '783 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('1db11854-c021-51a3-9ee2-cf33e525d6d3', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:a3cefadb-2668-4f12-830c-14518e0a08f3:edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0'), 'edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0', 'Yes, but I need the long-lens kit back from forensics by Thursday.', '[]'::jsonb, now() - interval '780 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('05766a13-4f88-5f9b-aba0-b983cfe8e873', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:a3cefadb-2668-4f12-830c-14518e0a08f3:edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0'), 'a3cefadb-2668-4f12-830c-14518e0a08f3', 'Maya signed it back in this morning. It''s in locker 7.', '[]'::jsonb, now() - interval '776 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('6f4765ee-16eb-5fa6-ba9e-cd951cda38dd', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:a3cefadb-2668-4f12-830c-14518e0a08f3:edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0'), 'edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0', 'Then we''re set. If the subject does the notary-Goldquay run again, that''s four consecutive Fridays — pattern threshold met.', '[]'::jsonb, now() - interval '773 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('b74cef5f-4e4f-511b-9876-e8fd1769d49d', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:a3cefadb-2668-4f12-830c-14518e0a08f3:edf4ac74-3e63-49cc-8bbb-71d9aa3c09b0'), 'a3cefadb-2668-4f12-830c-14518e0a08f3', 'And THEN we let legal do their thing. By the book on this one — she''s a lawyer, she''ll see anything sloppy.', '[]'::jsonb, now() - interval '770 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('c08339d3-30f0-5c95-8bdb-6a3a1c63f1ff', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:faf9aeda-e21e-42ab-80be-9ce0fd8662a1'), 'faf9aeda-e21e-42ab-80be-9ce0fd8662a1', 'Before Thursday: the TXN-0016 outlier — does it change Nightfall''s budget line? Six-figure settlements mean a bigger ring than we scoped.', '[]'::jsonb, now() - interval '424 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('73c73786-5b84-5971-ba98-b0042abf7cf7', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:faf9aeda-e21e-42ab-80be-9ce0fd8662a1'), '9878850d-3024-4012-b03a-d3d7ccef377c', 'Honestly, yes. If the fixer link verifies we''re looking at one network behind three operations. I''d rather re-scope now than mid-referral.', '[]'::jsonb, now() - interval '419 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('ca030bbd-b164-52b9-a4fa-b0242d822e45', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:faf9aeda-e21e-42ab-80be-9ce0fd8662a1'), 'faf9aeda-e21e-42ab-80be-9ce0fd8662a1', 'Then bring a consolidated proposal Thursday. One network, one task force, shared analyst pool.', '[]'::jsonb, now() - interval '414 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('0fa85b13-c522-5cd3-bb66-efb050e98109', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:faf9aeda-e21e-42ab-80be-9ce0fd8662a1'), '9878850d-3024-4012-b03a-d3d7ccef377c', 'Drafting it tonight. Working name: MERIDIAN GATE.', '[]'::jsonb, now() - interval '412 minutes', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.osionos_messages (id, channel_id, author_id, content, attachments, created_at, edited_at) VALUES ('263d97bc-f031-55ea-ae3a-880195184dc9', (SELECT id FROM public.osionos_channels WHERE dm_key = 'dm:9878850d-3024-4012-b03a-d3d7ccef377c:faf9aeda-e21e-42ab-80be-9ce0fd8662a1'), 'faf9aeda-e21e-42ab-80be-9ce0fd8662a1', 'Approved as a working name. And Marcus — good catch escalating the outlier fast.', '[]'::jsonb, now() - interval '409 minutes', NULL) ON CONFLICT (id) DO NOTHING;
